  bandage: {type: "item", stacksize: 40, specialinfo_en: "Heals 30 Health.", specialinfo_ko: "체력 30 회복.", deps: ["honey", "papyrus"]},
  bandage_butterflywings: {type: "item", stacksize: 40, craftingprefab: "walter", specialinfo_en: "Heals 24 health.\n\nIf used by Walter and he has learned the Field Medic skill, it will heal an additional 12 health, also restoring 10 sanity.", specialinfo_ko: "체력 24 회복.\n\n'현장 의료' 스킬을 배운 월터가 사용 시 체력 12와 정신력 10을 추가로 회복한다.", deps: ["butterflywings"]},
