  bat: {type: "creature", damage: 20, deps: ["batwing", "guano", "monstermeat"]},
  batbat: {type: "item", subcat: "weapon", weapondamage: 42.5, finiteuses: 75, specialinfo_en: "Each attack drains 6.8 Health from living targets.\n\nIf the user is not at full health, it also drains 3.4 Sanity.", specialinfo_ko: "살아있는 적을 공격 시 매 타격마다 체력 6.8 회복.\n\n최대 체력이 아니면 정신력도 3.4 감소.", deps: ["batwing", "livinglog", "purplegem"]},
  bathbomb: {type: "item", stacksize: 20, burnable: true, specialinfo_en: "Makes a hot spring all warm, steamy, and glassy when dropped in.", specialinfo_ko: "온천에 넣으면 온천이 따끈따끈하고 매끈매끈해진다.", deps: ["moon_tree_blossom", "nitre"]},
