  batnose_cooked: {type: "food", stacksize: 20, perishable: 4800, hungervalue: 18.75, healthvalue: 8, sanityvalue: 0, foodtype: "MEAT", deps: ["spoiled_food"]},
  batnosehat: {type: "item", subcat: "hat", dapperness: -0.022222222222222, perishable: 240, specialinfo_en: "Restores 3.9 Hunger every 5 seconds.", specialinfo_ko: "5초마다 허기 3.9 회복."},
  battlesong_container: {type: "item", subcat: "container", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "A carryable container with 8 slots that can hold Battle Songs and Battle Stingers.", specialinfo_ko: "전투의 노래와 전투의 함성을 담을 수 있는 8칸짜리 휴대용 보관함.", deps: ["beeswax", "boards", "feather_robin_winter", "goldnugget"]},
  battlesong_durability: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Reduce wear on your weapons by 25% while listening.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "이 노래를 듣고 있는 동안에는 무기의 내구도 소모가 25% 감소한다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "papyrus", "sewing_kit"]},
  battlesong_fireresistance: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Wigfrid and nearby allies will not take fire damage.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "위그프리드와 주변 아군들이 화염 피해를 입지 않는다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "oceanfish_small_9_inv", "papyrus"]},
  battlesong_healthgain: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Wigfrid and nearby allies will heal when fighting. Wigfrid will heal a little more too.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "주변의 아군들이 싸움으로 체력을 회복한다. 위그프리드의 체력 회복량 역시 소폭 늘어난다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["amulet", "featherpencil", "papyrus"]},
  battlesong_instant_panic: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Panic nearby enemies.\n\nThis is a Battle Stinger as it completes in an instant.", specialinfo_ko: "주변의 적들을 혼란에 빠뜨린다.\n\n부르는 즉시 발동되는 '전투의 함성'이다.", deps: ["featherpencil", "papyrus", "purplegem"]},
  battlesong_instant_revive: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Revive up to 2 nearby allied players.\n\nThis is a Battle Stinger as it completes in an instant.", specialinfo_ko: "주변의 아군 플레이어를 최대 2명 부활시킨다.\n\n부르는 즉시 발동되는 '전투의 함성'이다.", deps: ["featherpencil", "goose_feather", "papyrus"]},
  battlesong_instant_taunt: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Draw the attention of nearby enemies.\n\nThis is a Battle Stinger as it completes in an instant.", specialinfo_ko: "주변 적들의 주의를 끈다.\n\n부르는 즉시 발동되는 '전투의 함성'이다.", deps: ["featherpencil", "papyrus", "tomato"]},
  battlesong_lunaraligned: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Wigfrid and nearby allies take 10% less damage from Lunar Aligned enemies and deal 5% bonus damage to Shadow Aligned enemies.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "위그프리드와 아군들이 달 진영 몬스터에게 입는 데미지가 10% 감소하고 그림자 진영 몬스터에게 가하는 데미지가 5% 증가한다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "papyrus", "purebrilliance"]},
  battlesong_sanityaura: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Scary creatures seem about half as frightening when you're listening to this beautiful song.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "그 선율을 듣고 있으면 무서운 괴물도 절반만 무서워지는 아름다운 노래.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "nightmare_timepiece", "papyrus"]},
  battlesong_sanitygain: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Wigfrid and nearby allies will restore sanity when fighting.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "위그프리드와 주변 아군들이 전투를 통해 정신력을 회복한다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "moonbutterflywings", "papyrus"]},
  battlesong_shadowaligned: {type: "item", subcat: "battlesong", burnable: true, craftingprefab: "wathgrithr", specialinfo_en: "Wigfrid and nearby allies take 10% less damage from Shadow Aligned enemies and deal 5% bonus damage to Lunar Aligned enemies.\n\nThis is a Battle Song. Wigfrid must continue to sing for its benefit.", specialinfo_ko: "위그프리드와 아군들이 그림자 진영 몬스터에게 입는 데미지가 10% 감소하고 달 진영 몬스터에게 가하는 데미지가 5% 증가한다.\n\n위그프리드가 계속 불러야 효과를 누릴 수 있는 '전투의 노래'다.", deps: ["featherpencil", "horrorfuel", "papyrus"]},
