  bearger: {type: "giant", damage: 87.5, sanityaura: -1.6666666666667, deps: ["bearger_fur", "furtuft", "meat", "sketch", "winter_ornament_boss_bearger"]},
  bearger_fur: {type: "item", stacksize: 10, deps: ["furtuft"]},
  beargerfur_sack: {type: "item", specialinfo_en: "A carryable container with 6 slots that can hold prepared food.\n\nThe food stored in it will be preserved for a long time.", specialinfo_ko: "조리된 음식을 담을 수 있는 6칸짜리 휴대용 보관함.\n\n보관된 음식은 오랜 시간 동안 보존된다.", deps: ["bearger_fur", "moonrocknugget", "purebrilliance", "security_pulse_cage_full"]},
  beargervest: {type: "item", subcat: "clothing", dapperness: 0.074074074074074, insulator: 240, insulator_type: "winter", fueledmax: 3360, fueledrate: 1, fueledtype1: "USAGE", sewable: true, specialinfo_en: "Hunger rate is slowed by 25% when worn.", specialinfo_ko: "착용 시 허기 감소율 25% 감소.", deps: ["bearger_fur", "rope", "sweatervest"]},
  bedroll_furry: {type: "item", finiteuses: 3, burnable: true, specialinfo: "FURROLL", specialinfo_en: "Sleeping in it restores 1 Sanity and 1 health per second, costing 1 Hunger per second. It also warms the user overtime.", specialinfo_ko: "이것을 사용해 자면 초당 1의 정신력과 1의 체력을 회복하고 1의 허기가 감소한다. 체온 또한 서서히 상승한다.", deps: ["bedroll_straw", "manrabbit_tail"]},
  bedroll_straw: {type: "item", stacksize: 10, burnable: true, specialinfo: "STRAWROLL", specialinfo_en: "Sleeping in it restores 0.66 Sanity and 0.5 health per second, costing 1 Hunger per second.", specialinfo_ko: "이것을 사용해 자면 초당 0.66의 정신력과 0.66의 체력을 회복하고 1의 허기가 감소한다.", deps: ["cutgrass", "rope"]},
  bee: {type: "creature", subcat: "insect", damage: 10, stacksize: 20, perishable: 960, deps: ["honey", "stinger"]},
  beebox: {type: "thing", subcat: "structure", burnable: true, specialinfo_en: "If there are 6 or more flowers around a bee box, bees will produce honey inside the bee box.", specialinfo_ko: "벌통 주변에 꽃이 6송이 이상 있으면 벌통 안의 벌들이 꿀을 만든다.", deps: ["bee", "boards", "honey", "honeycomb"]},
  beebox_hermit: {type: "thing", subcat: "structure", specialinfo: "BEEBOX", specialinfo_en: "If there are 6 or more flowers around a bee box, bees will produce honey inside the bee box.", specialinfo_ko: "벌통 주변에 꽃이 6송이 이상 있으면 벌통 안의 벌들이 꿀을 만든다.", deps: ["bee", "honey", "honeycomb"]},
  beef_bell: {type: "item", subcat: "riding", specialinfo_en: "Name and bond with one Beefalo at a time. Bonded Beefalo will follow the holder, even into caves and offline.", specialinfo_ko: "한 번에 한 마리의 비팔로에게 이름을 지어주고 유대를 맺는다. 유대를 맺은 비팔로는 주인을 따라다니며, 동굴에 같이 갈 수도 있고 오프라인 시에도 같이 나간다.", deps: ["flint", "goldnugget"]},
  beefalo: {type: "creature", damage: 34, specialinfo_en: "Watch out for an aggressive mating season.\n\nFeed and care for one of these beasts, and maybe you can saddle them.", specialinfo_ko: "번식기에 공격적으로 변하는 것에 유의.\n\n밥을 주고 보살펴 주면 안장을 얹어 타고 다닐 수도 있다.", deps: ["beefalowool", "carrat", "horn", "meat", "poop"]},
  beefalo_groomer: {type: "thing", subcat: "riding", burnable: true, specialinfo: "BEEFALOGROOMER", specialinfo_en: "A survivor can hitch a bonded beefalo to this groomer, and then add or change the Beefalo's clothing.", specialinfo_ko: "결속된 비팔로를 몸단장대에 묶어두면 비팔로의 의상을 새로 입히거나 교체할 수 있다.", deps: ["beefalowool", "boards"]},
