  book_birds: {type: "item", subcat: "book", finiteuses: 3, burnable: true, craftingprefab: "wickerbottom", specialinfo_en: "Summon up to 20 birds to land nearby.", specialinfo_ko: "주변 지면에 최대 20마리의 새 소환.", deps: ["bird_egg", "papyrus"]},
  book_brimstone: {type: "item", subcat: "book", finiteuses: 5, burnable: true, craftingprefab: "wickerbottom", specialinfo_en: "Bring down over a dozen uncontrolled lightning strikes.", specialinfo_ko: "제어 불가능한 번개를 주변에 대량 소환.", deps: ["papyrus", "redgem"]},
  book_fire: {type: "item", subcat: "book", finiteuses: 3, burnable: true, craftingprefab: "wickerbottom", specialinfo_en: "Extinguishes all burning and smoldering fires nearby and creates or charges a Fiery Pen infused with that energy.", specialinfo_ko: "주변의 모든 불과 발화 직전의 연기를 꺼뜨리고 그 에너지로 불펜을 충전한다.", deps: ["book_brimstone", "featherpencil", "firepen", "papyrus"]},
