  book_horticulture: {type: "item", subcat: "book", finiteuses: 5, burnable: true, craftingprefab: "wickerbottom", specialinfo_en: "Rapidly grow up to 10 nearby garden plants or fruiting bushes.", specialinfo_ko: "주변의 밭 작물 혹은 식용 덤불을 최대 10개까지 급속 성장.", deps: ["papyrus", "poop", "seeds"]},
