  ghost: {type: "creature", damage: 15, sanityaura: -0.66666666666667},
  ghostflower: {type: "item", stacksize: 40, specialinfo_en: "Used by Wendy to craft Ghostly Elixirs.", specialinfo_ko: "웬디의 유령 비약 재료."},
  ghostflowerhat: {type: "item", subcat: "hat", dapperness: 0.055555555555556, perishable: 4800, craftingprefab: "wendy", specialinfo_en: "When equipped, allows Wendy to drink Elixirs herself.", specialinfo_ko: "착용하면 사람도 영약을 직접 먹을 수 있게 된다.", deps: ["ghostflower"]},
  ghostlyelixir_attack: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERATTACK", specialinfo_en: "Abigail will deal her nighttime damage during the day and dusk. Lasts 1 day.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nThe drinker can see in the dark as if they were a ghost.", specialinfo_ko: "아비게일이 낮과 저녁에도 밤의 공격력을 유지한다. 지속시간 1일.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n유령이 된 것처럼 어둠 속에서도 앞을 볼 수 있다.", deps: ["ghostflower", "stinger"]},
  ghostlyelixir_fastregen: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERHEALING", specialinfo_en: "Raises Abigail's health regeneration from 1 to 20 health per second. Lasts 30 seconds.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nHeals 5 health per second for 20 seconds.", specialinfo_ko: "아비게일의 체력 재생이 초당 1에서 20으로 증가한다. 지속시간 30초.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n20초 동안 초당 체력 5 회복", deps: ["ghostflower", "reviver"]},
  ghostlyelixir_lunar: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERLUNAR", specialinfo_en: "TODO", specialinfo_ko: "아비게일이 적에게 차원 피해를 추가로 10 입힌다. 게슈탈트 형태일 때는 추가 차원 피해가 100으로 증가한다.", deps: ["ghostflower", "purebrilliance"]},
  ghostlyelixir_retaliation: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERRETALIATION", specialinfo_en: "Doubles Abigail's shield duration from 0.5 seconds to 1 second.\n\nAttacking creatures also take 20 damage.\n\nLasts 1 day.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nGives the drinker a shield that will absorb a lot of damage from one hit and then goes on cool down for 10 seconds. It also inflicts 20 damage to all nearby enemies.", specialinfo_ko: "아비게일의 보호막 지속시간이 0.5초에서 1초로 증가한다.\n\n또한 피격 시 공격자에게 20의 피해를 준다.\n\n지속시간 1일.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n최대 10초마다 1번 큰 피해를 1회 막아주는 보호막을 얻는다. 보호막이 피해를 막아내면 모든 근처의 적들에게 20의 피해를 입힌다.", deps: ["ghostflower", "livinglog"]},
  ghostlyelixir_revive: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERREVIVE", specialinfo_en: "TODO", specialinfo_ko: "아비게일을 바로 3단계로 개화시킨다.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n정신력 조금과 허기 약간을 회복하고 부활에 의한 최대 체력 감소가 치료된다.", deps: ["forgetmelots", "ghostflower"]},
  ghostlyelixir_shadow: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERSHADOW", specialinfo_en: "TODO", specialinfo_ko: "아비게일의 '저주' 효과가 증폭되어, 저주에 걸린 대상은 피격 시 차원 피해 10을 추가로 받는다.", deps: ["ghostflower", "horrorfuel"]},
  ghostlyelixir_shield: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERSHIELD", specialinfo_en: "Doubles Abigail's shield duration from 0.5 seconds to 1 second. Lasts 1 day.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nGives the drinker a shield that will absorb a lot of damage from one hit and then goes on cool down for 10 seconds.", specialinfo_ko: "아비게일의 보호막 지속시간이 0.5초에서 1초로 증가한다.\n\n지속시간 1일.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n최대 10초마다 1번 큰 피해를 1회 막아주는 보호막을 얻는다.", deps: ["ghostflower", "log"]},
  ghostlyelixir_slowregen: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERREGENERATION", specialinfo_en: "Raises Abigail's health regeneration from 1 to 3 health per second. Lasts 1 day.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nHeals 1 health per second for 20 seconds.", specialinfo_ko: "아비게일의 체력 재생이 초당 1에서 3으로 증가한다. 지속시간 1일.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n20초 동안 초당 체력 1 회복", deps: ["ghostflower", "spidergland"]},
  ghostlyelixir_speed: {type: "item", subcat: "elixer", stacksize: 20, craftingprefab: "wendy", specialinfo: "GHOSTLYELIXERSPEED", specialinfo_en: "Abigail has a 75% speed boost for 1 day.\n\nWhen drunk by a non ghost wearing the Wraith's Wreath:\n\nHeavy objects won't slow the drinker down as much.", specialinfo_ko: "아비게일의 이동속도가 75% 증가한다. 지속시간 1일.\n\n망령 화관을 착용한 유령 외의 존재가 음용 시 효과:\n\n무거운 물건을 들었을 때 덜 느려진다.", deps: ["ghostflower", "honey"]},
  gift: {type: "item", burnable: true, specialinfo: "BUNDLE", specialinfo_en: "Can be unwrapped to release items inside.", specialinfo_ko: "풀면 안에 든 아이템이 나온다.", deps: ["ash"]},
