  heatrock: {type: "item", fueledmax: 100, fueledrate: 8, fueledtype1: "USAGE", fueleduses: true, sewable: true, specialinfo_en: "Gains heat when near something hot, and cools near something cold.\n\nIt will warm or cool the holder depending on its temperature.", specialinfo_ko: "뜨거운 것 주변에서는 뜨거워지고, 차가운 것 근처에서는 차가워진다.\n\n아이템의 온도에 따라 소유자의 체온이 오르고 내린다.", deps: ["flint", "pickaxe", "rocks"]},
