  hermit_bundle: {type: "item", burnable: true, specialinfo: "BUNDLE", specialinfo_en: "Can be unwrapped to release items inside.", specialinfo_ko: "풀면 안에 든 아이템이 나온다.", deps: ["ash"]},
  hermitcrab: {type: "POI", specialinfo_en: "This cantankerous crustacean isn't the easiest to get along with, but with a bit of time and care, you might just discover that there's more to her underneath that hard outer shell.", specialinfo_ko: "친해지기는 영 어려운 괴팍한 게. 하지만 약간의 시간과 노력을 들이면 단단한 겉껍데기 속의 내면은 다르다는 것을 알 수 있을 것이다.", deps: ["beebox_hermit", "hermit_bundle", "hermit_pearl", "hermitcrab_teashop", "meatrack_hermit", "winter_ornament_boss_hermithouse", "winter_ornament_boss_pearl"]},
