  lunar_forge: {type: "thing", subcat: "craftingstation", specialinfo: "LUNARFORGE", specialinfo_en: "Standing near this device will provide the survivor with new things they can craft that are based on Pure Brilliance.", specialinfo_ko: "이 장치 근처에 있으면 순수한 광휘 기반의 새로운 아이템을 제작할 수 있다.", deps: ["armor_lunarplant", "beargerfur_sack", "bomb_lunarplant", "deerclopseyeball_sentryward_kit", "houndstooth_blowpipe", "lunar_forge_kit", "lunarplant_kit", "lunarplanthat", "moonglass", "moonrocknugget", "pickaxe_lunarplant", "purebrilliance", "shovel_lunarplant", "slingshotammo_lunarplanthusk", "slingshotammo_purebrilliance", "staff_lunarplant", "sword_lunarplant"]},
  lunar_grazer: {type: "creature", subcat: "gestalt", damage: 50, planardamage: 10, lunar_aligned: true},
  lunar_seed: {type: "item", stacksize: 20, specialinfo_en: "They came from an enlightened crown - so return them to one, to bask in eternal enlightenment.", specialinfo_ko: "계몽의 왕관에서 떨어져 나온 물체. 계몽의 왕관에 되돌려 놓고 영구적인 계몽 효과를 누리도록 하자."},
  lunarfrog: {type: "creature", damage: 10, planardamage: 5, lunar_aligned: true, deps: ["froglegs", "lunarthrall_plant_gestalt"]},
  lunarplant_husk: {type: "item", stacksize: 20},
  lunarplant_kit: {type: "item", stacksize: 10, specialinfo: "LUNARPLANTKIT", specialinfo_en: "Will restore durability of tools and weapons crafted with Brightshade Husks.", specialinfo_ko: "빛말풀 거죽으로 만든 장비의 내구도를 회복한다.", deps: ["lunarplant_husk", "purebrilliance"]},
  lunarplanthat: {type: "item", subcat: "armor", armor: 830, absorb_percent: 0.8, armor_planardefense: 10, waterproofer: 0.35, specialinfo_en: "Glows in the dark and augments the Brightshade Staff with 2 more projectile bounces.\nAdds +5 Planar Damage to weapons with Planar Damage.", specialinfo_ko: "어둠 속에서 빛이 나고 빛말풀 지팡이의 투사체가 2회 더 튕긴다.\n차원 공격력이 있는 무기의 차원 공격력 +5.", forgerepairable: ["lunarplant_kit"], deps: ["lunarplant_husk", "lunarplant_kit", "purebrilliance"]},
  lunarrift_crystal_big: {type: "thing", specialinfo: "LUNARRIFTCRYSTAL", specialinfo_en: "A particularly hard material. Tools without special qualities may bounce off sometimes.", specialinfo_ko: "대단히 단단한 물질. 특별한 품질의 도구가 없으면 채광 도중 도구가 튕겨나갈 수 있다.", deps: ["purebrilliance"]},
  lunarrift_portal: {type: "thing", damage: 30, specialinfo: "LUNARRIFTPORTAL", specialinfo_en: "A one way door of moon energy that grows over time and then expires to pop up somewhere else some time later.", specialinfo_ko: "달 에너지가 방출되는 일방통행 포탈. 점점 성장했다가 사라진 뒤 언제 어딘가에서 다시 나타난다.", deps: ["lunar_grazer", "lunarrift_crystal_big"]},
  lunarthrall_plant: {type: "creature", damage: 100, planardamage: 30, lunar_aligned: true, specialinfo: "LUNARTHRALLPLANT", specialinfo_en: "Wraps itself around a growing plant blocking it from the survivors.", specialinfo_ko: "스스로를 자라나는 식물로 뒤덮어 몸을 보호한다.", deps: ["lunarplant_husk", "lunarthrall_plant_gestalt", "plantmeat"]},
  lunarthrall_plant_gestalt: {type: "creature", subcat: "gestalt", sanityaura: 0.66666666666667, lunar_aligned: true, deps: ["lunarrift_portal"]},
  lureplantbulb: {type: "item", stacksize: 10, burnable: true},
  lutefisk: {type: "item", subcat: "wintersfeastfood", finiteuses: 180, burnable: true, specialinfo: "WINTERSFEASTCOOKEDFOODS", specialinfo_en: "Captures the spirit of food when this is put on a Winter's Feast Table. The more, the merrier.", specialinfo_ko: "겨울 축제 탁자에 올려놓으면 진정한 맛을 느낄 수 있다. 많을수록 명절이 즐거워진다."},
  madscience_lab: {type: "thing", subcat: "craftingstation", specialinfo: "MADSCIENCELAB", specialinfo_en: "Standing near this device will provide the survivor with new Experiments they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 실험을 제작할 수 있다.", deps: ["cutstone", "halloweenpotion_bravery_large", "halloweenpotion_bravery_small", "halloweenpotion_embers", "halloweenpotion_health_large", "halloweenpotion_health_small", "halloweenpotion_moon", "halloweenpotion_sanity_large", "halloweenpotion_sanity_small", "halloweenpotion_sparks", "livingtree_root", "transistor"]},
  magician_chest: {type: "thing", subcat: "container", burnable: true, craftingprefab: "waxwell", specialinfo: "MAGICIANCHEST", specialinfo_en: "A 12 slot container that is actually a singular storage location that all \"magic storage\" items access.", specialinfo_ko: "12칸짜리 보관함 같지만, 사실 모든 \"마법 보관함\"과 공유하는 단일 저장 공간에 접근하는 용도.", deps: ["boards", "nightmarefuel", "silk"]},
  malbatross: {type: "giant", subcat: "bird", damage: 75, deps: ["bluegem", "malbatross_beak", "malbatross_feather", "mast_malbatross", "mast_malbatross_item", "meat", "premiumwateringcan", "sketch", "winter_ornament_boss_malbatross", "yellowgem"]},
  malbatross_beak: {type: "item", subcat: "weapon", weapondamage: 27.2, finiteuses: 1500, burnable: true, specialinfo: "PADDLE", specialinfo_en: "Can Row in water to move a boat in a desired direction.", specialinfo_ko: "물에서 노를 저어 원하는 방향으로 배를 움직인다."},
  malbatross_feather: {type: "item", stacksize: 20, burnable: true},
  malbatross_feathered_weave: {type: "item", stacksize: 20, burnable: true, deps: ["malbatross_feather", "silk"]},
