  mandrakesoup: {type: "food", stacksize: 40, perishable: 2880, hungervalue: 150, healthvalue: 100, sanityvalue: 5, foodtype: "VEGGIE", burnable: true, deps: ["spoiled_food"]},
  manrabbit_tail: {type: "food", stacksize: 40, hungervalue: 10, healthvalue: 10, sanityvalue: 0, foodtype: "HORRIBLE", burnable: true},
