  mashedpotatoes: {type: "food", stacksize: 40, perishable: 7200, hungervalue: 37.5, healthvalue: 20, sanityvalue: 33, foodtype: "VEGGIE", burnable: true, deps: ["spoiled_food"]},
  mask_ancient_architecthat: {type: "item", subcat: "costume", specialinfo_en: "Costume piece used in stage plays.\nIs it better to face the bitter truth or embrace sweet ignorance?", specialinfo_ko: "연극에 쓰이는 의상.\n씁쓸한 진실과 달콤한 무지, 둘 중 어느 쪽이 더 좋은 것일까?"},
  mask_ancient_handmaidhat: {type: "item", subcat: "costume", specialinfo_en: "Costume piece used in stage plays.\nShe did what was necessary in service of her Queen.", specialinfo_ko: "연극에 쓰이는 의상.\n그녀는 주군을 섬기기 위해 해야만 할 일을 했다."},
  mask_ancient_masonhat: {type: "item", subcat: "costume", specialinfo_en: "Costume piece used in stage plays.\nBetrayal begets the darkest of curses.", specialinfo_ko: "연극에 쓰이는 의상.\n배신은 가장 어두운 저주를 부르는 법이다."},
  mask_blacksmithhat: {type: "item", subcat: "costume", burnable: true, specialinfo: "COSTUME", specialinfo_en: "Costume piece used in stage plays.", specialinfo_ko: "연극에 쓰이는 의상.", deps: ["marble", "silk"]},
  mask_dollbrokenhat: {type: "item", subcat: "costume", burnable: true, specialinfo: "COSTUME", specialinfo_en: "Costume piece used in stage plays.", specialinfo_ko: "연극에 쓰이는 의상.", deps: ["marble", "silk"]},
