  mask_foolhat: {type: "item", subcat: "costume", burnable: true, specialinfo: "COSTUME", specialinfo_en: "Costume piece used in stage plays.", specialinfo_ko: "연극에 쓰이는 의상.", deps: ["marble", "silk"]},
  mask_halfwithat: {type: "item", subcat: "costume", armor: 2100, absorb_percent: 0.2, specialinfo: "COSTUME", specialinfo_en: "Costume piece used in stage plays.", specialinfo_ko: "연극에 쓰이는 의상.", deps: ["marble"]},
