  mermguard_shadow: {type: "creature", subcat: "merm", damage: "20-50", shadow_aligned: true, deps: ["mermguard_lunar", "mermking", "nightmarefuel"]},
  mermhat: {type: "item", subcat: "hat", dapperness: -0.022222222222222, perishable: 7200, craftingprefab: "wurt", specialinfo_en: "Merm will treat the wearer like a merm.", specialinfo_ko: "어인이 착용자를 어인으로 인식한다.", deps: ["cutreeds", "pondfish", "twigs"]},
  mermthrone: {type: "thing", burnable: true, specialinfo_en: "A nearby Merm will take up residence here and if fed, will grow into a King of Merms.", specialinfo_ko: "근처의 어인이 여기에 자리를 잡게 되었을 때 밥을 먹이면 어인왕이 된다.", deps: ["beefalowool", "kelp", "mermking", "pigskin"]},
  messagebottle: {type: "item", specialinfo_en: "Some messages are notes, some are maps to special locations.", specialinfo_ko: "쪽지가 적힌 것이 있고, 특별한 장소로 가는 지도가 그려진 게 있다.", deps: ["messagebottleempty"]},
  messagebottleempty: {type: "item", stacksize: 20, deps: ["gelblob_bottle"]},
  mighty_gym: {type: "thing", subcat: "structure", burnable: true, craftingprefab: "wolfgang", specialinfo: "MIGHTYGYM", specialinfo_en: "A structure constructable by Wolfgang to increase his Might by lifting at the right timing.\n\nIt requires two heavy objects be placed on its platforms to function. The higher the quality of the heavy objects, the more Might Wolfgang will get with each lift.", specialinfo_ko: "볼프강이 지을 수 있는 구조물. 적절한 타이밍에 리프팅을 하면 강인함이 증가한다.\n\n양 받침대에 각각 무거운 물체를 올려두어야 사용할 수 있다. 물체의 질이 높을수록 리프팅 한 번에 더 많은 강인함을 얻을 수 있다.", deps: ["boards", "cutstone", "potatosack", "rope"]},
  milkywhites: {type: "food", stacksize: 40, perishable: 4800, hungervalue: 12.5, healthvalue: 8, sanityvalue: -20, foodtype: "GENERIC", deps: ["spoiled_food"]},
