  miniboatlantern: {type: "item", fueledmax: 2880, fueledrate: 1, fueledtype1: "MAGIC", deps: ["lucky_goldnugget"]},
  minifan: {type: "item", subcat: "tool", weapondamage: 17, insulator: 60, insulator_type: "summer", fueledmax: 90, fueledrate: 1, fueledtype1: "BURNABLE", specialinfo_en: "Cools the holder while they run.", specialinfo_ko: "달리면 착용자의 체온을 낮춰줌.", deps: ["petals", "twigs"]},
  miniflare: {type: "item", burnable: true, specialinfo_en: "Creates a flash in the sky that can be seen by all survivors on the minimap.", specialinfo_ko: "미니맵에서 모든 생존자들이 볼 수 있는 섬광을 하늘로 쏘아올린다.", deps: ["cutgrass", "nitre", "twigs"]},
