  monkey_mediumhat: {type: "item", subcat: "hat", waterproofer: 0.2, fueledmax: 2880, fueledrate: 1, fueledtype1: "USAGE", sewable: true, specialinfo_en: "Reduces collision damage and decay damage on boats by half.", specialinfo_ko: "배의 충돌 피해와 노후화 피해를 절반으로 줄여준다."},
  monkey_smallhat: {type: "item", subcat: "hat", waterproofer: 0.2, fueledmax: 2880, fueledrate: 1, fueledtype1: "USAGE", sewable: true, specialinfo_en: "Wearer will perform boat activities faster and uses half as much oar durability.", specialinfo_ko: "착용 시 배의 기물 사용이 빨라지고 노의 내구도 소모가 절반으로 줄어든다."},
  monkeyisland_portal: {type: "thing", specialinfo: "MONKEYISLANDPORTAL", specialinfo_en: "A rift like spout from somewhere else, Monkeys and other debris keep dropping out of it.", specialinfo_ko: "어딘가로부터 원숭이와 잡동사니들이 뿜어져 나오는 균열.", deps: ["cutgrass", "dug_bananabush", "dug_monkeytail", "lightcrab", "monkeyisland_portal_debris", "palmcone_seed", "powder_monkey", "rocks", "twigs"]},
  monkeyqueen: {type: "POI", specialinfo_en: "This banana-obsessed monarch has a gift for lifting curses, and presiding over her motley crew of privateering primates.", specialinfo_ko: "바나나만 보면 환장하는 군주. 저주를 풀고 오합지졸 원숭이 사략꾼들을 이끄는 능력을 가졌다.", deps: ["dock_kit"]},
  monkeytail: {type: "thing", burnable: true, specialinfo: "NEEDFERTILIZER", specialinfo_en: "Needs fertilization if transplanted.", specialinfo_ko: "옮겨심은 뒤에는 거름을 줘야 한다.", deps: ["cutreeds", "dug_monkeytail"]},
  monsterlasagna: {type: "food", stacksize: 40, perishable: 2880, hungervalue: 37.5, healthvalue: -20, sanityvalue: -20, foodtype: "MEAT", burnable: true, deps: ["spoiled_food"]},
