  moon_altar_astral: {type: "thing", subcat: "structure", specialinfo: "MOONALTAR", specialinfo_en: "Standing near this device will provide the survivor with new things they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 아이템을 제작할 수 있다.", repairitems: ["moon_altar_ward"], deps: ["moon_altar_icon", "moon_altar_link", "moon_altar_ward", "moon_fissure"]},
  moon_altar_cosmic: {type: "thing", subcat: "craftingstation", specialinfo: "MOONALTAR", specialinfo_en: "Standing near this device will provide the survivor with new things they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 아이템을 제작할 수 있다.", deps: ["bathbomb", "carpentry_blade_moonglass", "glasscutter", "lunar_forge_kit", "moon_altar_crown", "moon_altar_link", "moon_fissure", "moon_mushroomhat", "moonglassaxe", "moonrockidol", "multiplayer_portal_moonrock_constr_plans", "sketch", "slingshotammo_moonglass", "turf_fungus_moon", "turf_meteor"]},
