  moon_altar_rock_glass: {type: "thing", specialinfo: "MOON_ALTAR_ROCK", specialinfo_en: "An object trapped inside moon rock.", specialinfo_ko: "월석 속에 박혀있는 물체.", deps: ["moon_altar_glass"]},
