  moon_device: {type: "thing", subcat: "structure", specialinfo: "MOONDEVICE", specialinfo_en: "A complex contraption to contain a geyser of energy that has several stages of construction.", specialinfo_ko: "솟구치는 에너지를 가두기 위한 복잡한 장치. 여러 단계에 거쳐 건설하게 되어 있다.", deps: ["alterguardian_phase1"]},
  moon_fissure: {type: "thing", sanityaura: 0.83333333333333, repairitems: ["moon_altar_icon", "moon_altar_crown", "moon_altar_glass"], deps: ["moon_altar", "moon_altar_cosmic"]},
  moon_mushroomhat: {type: "item", subcat: "hat", waterproofer: 0.2, insulator: 60, insulator_type: "summer", perishable: 2880, specialinfo: "MUSHHAT", specialinfo_en: "Reduces hunger by 25%. Periodically Spawns Mushroom Spores.", specialinfo_ko: "허기 소모량 25% 감소. 주기적으로 버섯 포자를 생성.", deps: ["moon_cap", "red_mushroomhat", "spore_moon"]},
  moon_tree_blossom: {type: "food", stacksize: 40, perishable: 2880, hungervalue: 0, healthvalue: 1, sanityvalue: 0, foodtype: "VEGGIE", burnable: true, deps: ["moon_tree_blossom_dried", "spoiled_food"]},
  moon_tree_blossom_dried: {type: "food", stacksize: 40, hungervalue: 0, healthvalue: 1, sanityvalue: 10, foodtype: "VEGGIE", burnable: true},
  moon_tree_tall: {type: "thing", subcat: "tree", burnable: true, specialinfo: "TREE", specialinfo_en: "Standing near a tree offers 35% protection from rain and cools survivor a small amount.", specialinfo_ko: "나무 근처에 있으면 비를 35% 덜 맞고 더위를 조금 덜 수 있다.", deps: ["charcoal", "log", "moon_tree_blossom", "moonbutterfly"]},
  moonbase: {type: "POI", specialinfo_en: "\"'Neath full moon's light, ye place the key;\nA rod whose call the stars doth heed.\nBut be ye warned, 'fore prize be claimed,\nSurvive the horde, lest ye be maimed.\"", specialinfo_ko: "\"찬란한 만월 아래 열쇠를 꽂을지니,\n별빛을 불러내는 지팡이가 그 열쇠.\n명심해 둘지어다, 보물을 찾는 자여,\n군세를 물리치지 못하면 쓰러지리\"", repairitems: ["moonrockcrater", "wall_moonrock_item", "moonrocknugget"], deps: ["moonrock_pieces", "moonrocknugget"]},
  moonbutterfly: {type: "creature", subcat: "insect", stacksize: 20, perishable: 240, lunar_aligned: true, deps: ["moonbutterfly_sapling", "moonbutterflywings"]},
