  moondial: {type: "thing", subcat: "structure", specialinfo_en: "The level of water reflects the current and upcoming state of the moon, overflowing with water during a full moon.", specialinfo_ko: "수면에 오늘의 달의 상태가 비춰진다. 물이 넘치면 보름달인 것.", deps: ["bluemooneye", "ice", "moonglass", "moonrocknugget"]},
  moonglass: {type: "item", subcat: "element", stacksize: 40, hungervalue: 12.5, healthvalue: 1, sanityvalue: 0, foodtype: "LUNAR_SHARDS"},
  moonglass_charged: {type: "item", subcat: "element", stacksize: 40, perishable: 720, hungervalue: 12.5, healthvalue: 1, sanityvalue: 0, foodtype: "LUNAR_SHARDS", deps: ["moonglass"]},
  moonglassaxe: {type: "item", subcat: "tool", weapondamage: 34, finiteuses: 80, deps: ["moonglass", "twigs"]},
  moonrockcrater: {type: "item", specialinfo: "CRATEREDMOONROCK", specialinfo_en: "Contains a gem-shaped socket.", specialinfo_ko: "보석 모양의 홈이 파여 있다.", deps: ["bluemooneye", "greenmooneye", "moonrocknugget", "orangemooneye", "purplemooneye", "redmooneye", "yellowmooneye"]},
  moonrockidol: {type: "item", specialinfo_en: "When used at a Celestial Portal, the survivor can change to a different survivor.", specialinfo_ko: "천상의 포탈에 사용 시 생존자를 다른 생존자로 바꿀 수 있다.", deps: ["moonrocknugget", "purplegem"]},
  moonrocknugget: {type: "item", subcat: "element", stacksize: 40, hungervalue: 1, healthvalue: 10, sanityvalue: 0, foodtype: "ELEMENTAL"},
  moonrockseed: {type: "item", subcat: "craftingstation", specialinfo_en: "Standing near this device will provide the survivor with new items they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 아이템을 제작할 수 있다.", deps: ["bathbomb", "moon_mushroomhat", "moonrockidol", "multiplayer_portal_moonrock_constr_plans"]},
  moonstorm_goggleshat: {type: "item", subcat: "hat", dapperness: 0.055555555555556, waterproofer: 0.2, fueledmax: 480, fueledrate: 1, fueledtype1: "USAGE", sewable: true, specialinfo_en: "Improves vision in a storm.\n\nWill help locate mysterious holograms.", specialinfo_ko: "폭풍 속에서도 잘 보이게 된다.\n\n의문의 홀로그램을 추적하는 것을 도와준다.", deps: ["moonglass", "potato"]},
  moonstorm_spark: {type: "item", damage: 10, stacksize: 20, perishable: 360},
  moonstorm_static: {type: "thing", specialinfo: "MOONSTORMSTATIC", specialinfo_en: "An experiment being worked on by a mysterious hologram that requires the survivors help.", specialinfo_ko: "의문의 홀로그램이 생존자들의 도움을 받아 진행하는 실험.", deps: ["moonstorm_static_item"]},
  moonstorm_static_catcher: {type: "item", stacksize: 10, specialinfo_en: "Now you're the catcher!\nFind the energy running loose in the storms and try to restrain it.", specialinfo_ko: "이제는 내가 직접 잡는다!\n폭풍 속에서 제멋대로 돌아다니는 에너지를 찾아 억제해 보자."},
  moose: {type: "giant", subcat: "bird", damage: 75, deps: ["drumstick", "goose_feather", "meat", "mooseegg", "mossling", "sketch", "winter_ornament_boss_moose"]},
  moqueca: {type: "food", stacksize: 40, perishable: 3840, hungervalue: 112.5, healthvalue: 60, sanityvalue: 33, foodtype: "MEAT", burnable: true, deps: ["spoiled_food"]},
  mosquito: {type: "creature", subcat: "insect", damage: 3, stacksize: 20, perishable: 960, deps: ["mosquitosack"]},
  mosquitobomb: {type: "item", subcat: "weapon", weapondamage: 59.5, weaponrange: 10, stacksize: 20, craftingprefab: "wurt", specialinfo_en: "Packed so tight with wriggling friends that the explosive release of bugs inflicts damage to targets nearby.", specialinfo_ko: "꿈틀거리는 친구들이 꽉 차 있다. 착탄 지점에 근처의 목표를 공격하는 벌레 무리를 풀어놓는다.", deps: ["mosquito", "mosquitosack"]},
