  pocketwatch_heal: {type: "item", subcat: "pocketwatch", craftingprefab: "wanda", specialinfo_en: "Rewinds Wanda's age 8 years. 2 minute cooldown.", specialinfo_ko: "완다의 나이를 8년 되감는다. 쿨타임 2분.", deps: ["marble", "pocketwatch_parts", "redgem"]},
  pocketwatch_parts: {type: "item", stacksize: 20, craftingprefab: "wanda", deps: ["nightmarefuel", "pocketwatch_dismantler", "thulecite_pieces"]},
  pocketwatch_portal: {type: "item", subcat: "pocketwatch", craftingprefab: "wanda", specialinfo_en: "Used to mark a spot, and then used again to open a portal to that spot that lasts for 10 seconds.\n\nUsing the portal costs 20 Sanity.\n\nThe Rift Watch will become a Backtrek Watch after use.", specialinfo_ko: "특정 지점을 지정해 두었다가, 사용 시 해당 지점으로 향하는 포탈을 10초 동안 생성한다.\n\n포탈 사용 시 정신력 20 소모.\n\n사용한 균열의 시계는 회귀의 시계로 바뀐다.", deps: ["pocketwatch_recall", "purplegem"]},
  pocketwatch_recall: {type: "item", subcat: "pocketwatch", craftingprefab: "wanda", specialinfo_en: "Used to mark a spot, and then used again to teleport to that spot.\n\n8 minute cooldown. Even works between the Cave and the Forest.", specialinfo_ko: "특정 지점을 지정해 두었다가, 사용 시 해당 지점으로 순간이동한다.\n\n쿨타임 8분. 동굴과 지상 사이를 오갈 수도 있다.", deps: ["goldnugget", "pocketwatch_parts", "walrus_tusk"]},
  pocketwatch_revive: {type: "item", subcat: "pocketwatch", craftingprefab: "wanda", specialinfo_en: "Wanda can haunt the watch as a ghost to revive herself, breaking the watch. The watch can be used on a Survivor's skeleton to revive them at the skeleton. 4 minute cooldown.", specialinfo_ko: "완다가 유령 상태에서 빙의하면 부활하는 대신 시계가 부서진다. 생존자의 해골에 사용 시 생존자를 해골 위치에서 부활시킨다. 쿨타임 4분.", deps: ["boneshard", "livinglog", "pocketwatch_parts"]},
  pocketwatch_warp: {type: "item", subcat: "pocketwatch", craftingprefab: "wanda", specialinfo_en: "Teleports Wanda to the location marked on the ground.\n\nThe younger wanda is, the further back in time the marked location will be. Wanda is invulnerable for a short time during the teleport.\n\n2 second cooldown.", specialinfo_ko: "완다가 땅에 표시된 지점으로 순간이동한다.\n\n완다가 젊을수록 더 먼 지점이 표시된다. 순간이동 중에는 잠시 무적.\n\n쿨타임 2초.", deps: ["goldnugget", "pocketwatch_parts"]},
  pocketwatch_weapon: {type: "item", subcat: "pocketwatch", weapondamage: 81.6, weaponrange: 2, fueledmax: 720, fueledrate: 7.5, fueledtype1: "NIGHTMARE", fueleduses: true, craftingprefab: "wanda", specialinfo_en: "When the fuel reaches 0, its damage drops to 27.", specialinfo_ko: "연료가 떨어지면 피해량이 27로 감소한다.", deps: ["marble", "nightmarefuel", "pocketwatch_parts"]},
  polishcookie: {type: "item", subcat: "wintersfeastfood", finiteuses: 180, burnable: true, specialinfo: "WINTERSFEASTCOOKEDFOODS", specialinfo_en: "Captures the spirit of food when this is put on a Winter's Feast Table. The more, the merrier.", specialinfo_ko: "겨울 축제 탁자에 올려놓으면 진정한 맛을 느낄 수 있다. 많을수록 명절이 즐거워진다."},
  polly_rogers: {type: "creature", subcat: "bird", specialinfo: "POLLYROGERS", specialinfo_en: "Gathers loot nearby.", specialinfo_ko: "근처의 아이템을 주워온다."},
  polly_rogershat: {type: "item", subcat: "hat", waterproofer: 0.35, fueledmax: 2880, fueledrate: 1, fueledtype1: "USAGE", sewable: true, specialinfo_en: "Polly Roger will fly down and follow the wearer, fetching nearby items.", specialinfo_ko: "폴리 로저가 착용자 주위를 날아다니며 아이템을 주워다 준다.", deps: ["blackflag", "feather_canary", "monkey_mediumhat", "polly_rogers"]},
  pomegranate: {type: "food", stacksize: 40, perishable: 2880, hungervalue: 9.375, healthvalue: 3, sanityvalue: 0, foodtype: "VEGGIE", burnable: true, deps: ["pomegranate_cooked", "pomegranate_oversized", "pomegranate_seeds", "spoiled_food"]},
  pomegranate_cooked: {type: "food", stacksize: 40, perishable: 1440, hungervalue: 12.5, healthvalue: 20, sanityvalue: 0, foodtype: "VEGGIE", burnable: true, deps: ["spoiled_food"]},
  pomegranate_oversized: {type: "item", perishable: 11520, burnable: true, deps: ["beeswax", "pomegranate", "pomegranate_seeds"]},
