  pond_cave: {type: "thing", specialinfo: "PONDCAVE", specialinfo_en: "If filled with acid, this pond will crust over with Nitre.", specialinfo_ko: "산성 물질이 차면 연못이 초석으로 뒤덮인다.", deps: ["nitre", "pondeel"]},
  pondeel: {type: "food", perishable: 1440, hungervalue: 9.375, healthvalue: 3, sanityvalue: 0, foodtype: "MEAT", deps: ["eel", "eel_cooked", "fishmeat_small", "fishmeat_small_cooked"]},
  pondfish: {type: "food", perishable: 1440, hungervalue: 12.5, healthvalue: 1, sanityvalue: 0, foodtype: "MEAT", deps: ["eel", "fishmeat_small", "fishmeat_small_cooked"]},
  poop: {type: "item", stacksize: 20, burnable: true},
  portableblender: {type: "thing", subcat: "craftingstation", burnable: true, specialinfo_en: "Standing near this device will provide the survivor with new Seasonings they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 양념을 제작할 수 있다.", deps: ["ash", "goldnugget", "portableblender_item", "spice_chili", "spice_garlic", "spice_salt", "spice_sugar", "transistor", "twigs"]},
  portablecookpot: {type: "thing", subcat: "structure", burnable: true, specialinfo_en: "A 4 slot container that will receive ingredients for food.\n\nPlacing 4 items in the container will allow them to be cooked creating some kind of food depending on the items put in to begin with.\n\nIt can be dismantled back into an inventory item.", specialinfo_ko: "식재료를 넣을 수 있는 4칸짜리 보관함.\n\n아이템을 4개 넣으면 요리를 통해 넣은 재료에 따라 여러 종류의 음식을 만들 수 있다.\n\n인벤토리 아이템으로 다시 해체하는 것도 가능.", deps: ["ash", "asparagussoup", "baconeggs", "bananajuice", "bananapop", "barnaclepita", "barnaclestuffedfishhead", "barnaclesushi", "barnaclinguine", "batnosehat", "beefalofeed", "beefalotreat", "bonesoup", "bonestew", "bunnystew", "butterflymuffin", "californiaroll", "ceviche", "charcoal", "dragonchilisalad", "dragonpie", "dustmeringue", "figatoni", "figkabab", "fishsticks", "fishtacos", "flowersalad", "freshfruitcrepes", "frogfishbowl", "frogglebunwich", "frognewton", "frozenbananadaiquiri", "fruitmedley", "gazpacho", "glowberrymousse", "goldnugget", "guacamole", "honeyham", "honeynuggets", "hotchili", "icecream", "jammypreserves", "jellybean", "justeggs", "kabobs", "koalefig_trunk", "leafloaf", "leafymeatburger", "leafymeatsouffle", "lobsterbisque", "lobsterdinner", "mandrakesoup", "mashedpotatoes", "meatballs", "meatysalad", "monsterlasagna", "monstertartare", "moqueca", "nightmarepie", "pepperpopper", "perogies", "portablecookpot_item", "potatosouffle", "potatotornado", "powcake", "pumpkincookie", "ratatouille", "salsa", "seafoodgumbo", "shroombait", "shroomcake", "stuffedeggplant", "surfnturf", "sweettea", "taffy", "talleggs", "trailmix", "turkeydinner", "twigs", "unagi", "veggieomlet", "vegstinger", "voltgoatjelly", "waffles", "watermelonicle", "wetgoop"]},
  portablefirepit_item: {type: "item", burnable: true, craftingprefab: "walter", specialinfo_en: "A portable campfire that stays lit even when packed!", specialinfo_ko: "휴대용 모닥불. 포장해 두어도 불이 꺼지지 않는다!", deps: ["log", "rocks", "rope"]},
  portablespicer: {type: "thing", subcat: "structure", burnable: true, specialinfo_en: "A container with 2 slots. One for a prepared food dish and one for a Seasoning.\n\nIf filled with one of each, it will spice the food with the provided seasoning.", specialinfo_ko: "2칸짜리 보관함. 한 칸은 조리된 음식용, 한 칸은 조미료용.\n\n각 칸을 채우면 음식에 해당 조미료를 뿌려준다.", deps: ["ash", "cutstone", "goldnugget", "portablespicer_item", "twigs"]},
  portabletent: {type: "thing", subcat: "structure", finiteuses: 10, burnable: true, specialinfo_en: "Sleeping in the tent restores 1 Sanity and 2 health per second, but costs 1 Hunger per second.\n\nAs a Pinetree Pioneer, it costs Walter 1 Hunger every 2 seconds instead.\n\nAlso wetness is reduced 1 per second as well temperature is raised to 40 degrees, at 1 degree per second.", specialinfo_ko: "이 텐트에서 자면 초당 1의 정신력과 2의 체력을 회복하고 1의 허기가 감소한다.\n\n월터는 소나무 개척단이어서 그 대신 2초마다 1의 허기가 감소한다.\n\n습기 역시 초당 1씩 감소하고 체온도 초당 1도씩, 최대 40도까지 상승한다.", deps: ["portabletent_item"]},
  portabletent_item: {type: "item", finiteuses: 10, burnable: true, craftingprefab: "walter", deps: ["bedroll_straw", "portabletent", "rope", "twigs"]},
