  researchlab3: {type: "thing", subcat: "craftingstation", burnable: true, specialinfo: "SCIENCEPROTOTYPER", specialinfo_en: "Standing near this device will provide the survivor with new things they can craft.\n\nCrafting something new for the first time gives a boost of 15 Sanity.\n\nOnce an item is crafted, the survivor will know how to craft that item even away from the machine.", specialinfo_ko: "장치 주변에 있으면 새로운 아이템을 제작할 수 있다.\n\n무언가를 처음으로 만들면 정신력을 15 회복한다.\n\n한 번 제작한 아이템은 장치에서 떨어져 있을 때도 제작할 수 있다.", deps: ["amulet", "armor_sanity", "armorslurper", "batbat", "blueamulet", "book_brimstone", "book_sleep", "firestaff", "icestaff", "livinglog", "moondial", "nightlight", "nightmarefuel", "nightsword", "onemanband", "panflute", "pocketwatch_portal", "pocketwatch_recall", "pocketwatch_weapon", "punchingbag_lunar", "punchingbag_shadow", "purpleamulet", "purplegem", "resurrectionstatue", "sentryward", "slingshotammo_freeze", "slingshotammo_slow", "telebase", "telestaff"]},
  researchlab4: {type: "thing", subcat: "craftingstation", burnable: true, specialinfo: "SCIENCEPROTOTYPER", specialinfo_en: "Standing near this device will provide the survivor with new things they can craft.\n\nCrafting something new for the first time gives a boost of 15 Sanity.\n\nOnce an item is crafted, the survivor will know how to craft that item even away from the machine.", specialinfo_ko: "장치 주변에 있으면 새로운 아이템을 제작할 수 있다.\n\n무언가를 처음으로 만들면 정신력을 15 회복한다.\n\n한 번 제작한 아이템은 장치에서 떨어져 있을 때도 제작할 수 있다.", deps: ["amulet", "blueamulet", "boards", "book_sleep", "icestaff", "moondial", "nightlight", "nightmarefuel", "onemanband", "panflute", "pocketwatch_portal", "pocketwatch_recall", "punchingbag_lunar", "punchingbag_shadow", "purplegem", "rabbit", "researchlab3", "resurrectionstatue", "sentryward", "slingshotammo_freeze", "tophat"]},
  reskin_tool: {type: "item", burnable: true, specialinfo: "RESKINTOOL", specialinfo_en: "Cycles through the skins on in-world items.", specialinfo_ko: "월드 안의 아이템의 스킨을 돌아가며 바꾼다.", deps: ["petals", "twigs"]},
  resurrectionstatue: {type: "thing", subcat: "structure", burnable: true, specialinfo: "RESURECTIONSTATUE", specialinfo_en: "Once constructed, a single survivor can attune themselves to it for the cost of 40 Health.\n\nAfter attuning, when the survivor becomes as ghost, they can use the special button on the screen to respawn at the Effigy's location and it is destroyed.", specialinfo_ko: "체력 40을 소모하여 동조할 수 있다. 우상 한 개당 한 명만 동조 가능.\n\n동조된 상태에서 생존자가 유령이 되면 화면에 생기는 전용 버튼을 눌러 우상이 있는 곳에서 부활할 수 있다. 사용된 우상은 파괴된다.", deps: ["beardhair", "boards", "charcoal"]},
  resurrectionstone: {type: "POI", specialinfo_en: "Tired of getting dead? Leave your worries behind by finding a handy Touch Stone!", specialinfo_ko: "죽는 것에 지쳤을 때는 편리한 부활 제단만 찾으면 걱정 끝!", deps: ["marble", "nightmarefuel", "rocks"]},
  reviver: {type: "item", specialinfo_en: "Gives the user 80 Sanity when given to a survivor's ghost.\n\nThe ghost will revive with a 25% max health penalty which can be recovered with a Booster Shot.", specialinfo_ko: "생존자 유령에게 주면 정신력 80 회복.\n\n유령은 최대 체력이 25% 깎인 채로 부활한다. 깎인 최대 체력은 예방주사로 회복 가능.", deps: ["cutgrass", "spidergland"]},
  roastturkey: {type: "item", subcat: "wintersfeastfood", finiteuses: 180, burnable: true, specialinfo: "WINTERSFEASTCOOKEDFOODS", specialinfo_en: "Captures the spirit of food when this is put on a Winter's Feast Table. The more, the merrier.", specialinfo_ko: "겨울 축제 탁자에 올려놓으면 진정한 맛을 느낄 수 있다. 많을수록 명절이 즐거워진다."},
