  soil_amender: {type: "item", perishable: 1440, specialinfo: "SOILAMENDER", specialinfo_en: "Adds 8-32 Growth Formula nutrient to the ground depending in its fermentation level.\n\nWill also trigger Wormwoods bloom for 1 to 4 minutes depending on fermentation level.", specialinfo_ko: "발효 단계에 따라 흙에 8~32의 성장 촉진제 양분 보충.\n\n웜우드는 발효 단계에 따라 1분~4분 동안 개화한다.", deps: ["ash", "kelp", "messagebottleempty", "soil_amender_fermented"]},
