  spear_wathgrithr_lightning_charged: {type: "item", subcat: "weapon", planardamage: 20, finiteuses: 200, specialinfo_en: "Does electrical damage which does more damage to wet targets.\n\nIncreases movement speed by 20% when held.\n\nIt can only be equipped by Wigfrids who have the \"Elding Spear Enhancement II\" skill.", specialinfo_ko: "젖은 상대에게 더 큰 피해를 주는 전기 공격을 가한다.\n\n착용 시 이동속도 20% 증가.\n\n\"뇌전창 강화 II\" 스킬을 배운 위그프리드만 착용할 수 있다."},
  spice_chili: {type: "item", stacksize: 40, craftingprefab: "warly", specialinfo_en: "Can be added to Crock Pot food using a Portable Seasoning Station.\n\nEating a dish spiced with Chili Flakes adds 20% damage to their attacks.\n\nDuration 4 minutes.\n\nAlso raises temperature 15 degrees for 15 seconds.", specialinfo_ko: "휴대용 양념기에서 요리솥 음식에 첨가 가능.\n\n고춧가루로 양념한 음식 섭취 시 공격력 20% 증가.\n\n지속시간 4분.\n\n15초 동안 체온도 15 상승.", deps: ["pepper"]},
  spice_garlic: {type: "item", stacksize: 40, craftingprefab: "warly", specialinfo_en: "Can be added to Crock Pot food using a Portable Seasoning Station.\n\nEating a dish spiced with Garlic reduces the damage they take to their health by 33%.\n\nDuration 4 minutes.", specialinfo_ko: "휴대용 양념기에서 요리솥 음식에 첨가 가능.\n\n마늘로 양념한 음식 섭취 시 받는 데미지 33% 감소.\n\n지속시간 4분.", deps: ["garlic"]},
  spice_salt: {type: "item", stacksize: 40, craftingprefab: "warly", specialinfo_en: "Can be added to Crock Pot food using a Portable Seasoning Station.\n\nEating a dish spiced with Seasoning Salt grants 25% more healing for healing effects.\n\nDuration 4 minutes.", specialinfo_ko: "휴대용 양념기에서 요리솥 음식에 첨가 가능.\n\n소금으로 양념한 음식은 체력 회복량이 25% 높다.", deps: ["saltrock"]},
  spice_sugar: {type: "item", stacksize: 40, craftingprefab: "warly", specialinfo_en: "Can be added to Crock Pot food using a Portable Seasoning Station.\n\nEating a dish spiced with Honey Crystals doubles their rate of Mining Chopping and Hammering.\n\nDuration 4 minutes.", specialinfo_ko: "휴대용 양념기에서 요리솥 음식에 첨가 가능.\n\n꿀 결정으로 양념한 음식 섭취 시 채광, 벌목, 망치질의 능률이 2배로 증가.\n\n지속시간 4분.", deps: ["honey"]},
  spicepack: {type: "item", subcat: "backpack", burnable: true, craftingprefab: "warly", specialinfo_en: "A 6 slots container that slows the spoiling of items inside.", specialinfo_ko: "보관 중인 아이템의 부패를 늦추는 6칸짜리 가방.", deps: ["ash", "cutgrass", "nitre", "twigs"]},
  spider: {type: "creature", subcat: "spider", damage: 20, perishable: 2400, sanityaura: -0.41666666666667, deps: ["monstermeat", "silk", "spidergland"]},
