  spider_healer: {type: "creature", subcat: "spider", damage: 10, perishable: 2400, sanityaura: -0.41666666666667, specialinfo_en: "Heals Webber for 8 Health and spiders in an area for 80 Health.", specialinfo_ko: "웨버의 체력 8 회복, 주변 거미의 체력 80 회복.", deps: ["monstermeat", "silk", "spider_healer_item", "spidergland"]},
