  spider_whistle: {type: "item", finiteuses: 40, burnable: true, craftingprefab: "webber", specialinfo: "SPIDERWHISTLE", specialinfo_en: "Webber can use the whistle to wake up nearby spiders and spider dens.\n\nNearby spiders will stop attacking their targets and will also temporarily ignore food on the ground.", specialinfo_ko: "웨버가 불면 주변의 거미나 거미집이 깨어난다.\n\n근처의 거미들이 공격을 멈추고 바닥의 음식을 잠시 무시한다.", deps: ["silk", "twigs"]},
  spiderden: {type: "thing", subcat: "structure", burnable: true, specialinfo_en: "Creates a patch of webbing on the ground near it that slows survivors and some creatures that walk on it.\n\nComes in several sizes and grows to fit its spider population.\n\nWebber may upgrade these with Silk.", specialinfo_ko: "주변 바닥에 생존자와 몇몇 생물의 이동 속도를 느리게 하는 거미줄이 깔린다.\n\n크기가 단계적으로 성장하고, 그에 따라 안의 거미 수도 늘어난다.\n\n웨버는 거미줄로 거미집을 업그레이드할 수 있다.", deps: ["silk", "spider", "spider_warrior", "spidereggsack", "spiderqueen"]},
  spiderden_bedazzler: {type: "item", finiteuses: 5, burnable: true, craftingprefab: "webber", specialinfo: "DENBEDAZZLER", specialinfo_en: "Bedazzle a Spider Den to pacify the spiders nearby. Bedazzled dens do not grow.", specialinfo_ko: "거미집을 장식하면 주변의 거미들이 우호화된다. 장식된 거미집은 성장하지 않는다.", deps: ["boards", "papyrus", "silk"]},
  spidereggsack: {type: "item", stacksize: 10, burnable: true, craftingprefab: "webber", specialinfo: "PLANTABLE_ON", specialinfo_en: "Can be planted on the ground.", specialinfo_ko: "땅에 심을 수 있음.", deps: ["papyrus", "silk", "spiderden", "spidergland"]},
  spidergland: {type: "item", stacksize: 20, burnable: true, specialinfo_en: "Heals 8 Health when used on survivors or creatures.", specialinfo_ko: "생존자나 생물에 사용 시 체력 8 회복."},
  spiderhat: {type: "item", subcat: "hat", dapperness: -0.033333333333333, waterproofer: 0.2, fueledmax: 120, fueledrate: 1, fueledtype1: "USAGE", specialinfo_en: "Up to 10 Spiders nearby will follow the wearer, but creatures who attack spiders will also attack the wearer.\n\nDoes not work on Spiders spawned by a Spider Queen.", specialinfo_ko: "착용 시 주변의 거미 10마리가 따라다닌다. 거미를 적대하는 생물은 착용자도 적대한다.\n\n여왕 거미에게서 나온 거미에게는 적용되지 않음.", deps: ["monstermeat", "silk", "spidergland"]},
