  sword_lunarplant: {type: "item", subcat: "weapon", planardamage: 30, weapondamage: 38, finiteuses: 200, forgerepairable: ["lunarplant_kit"], deps: ["lunarplant_husk", "lunarplant_kit", "purebrilliance"]},
  table_winters_feast: {type: "thing", subcat: "structure", burnable: true, specialinfo: "TABLEWINTERSFEAST", specialinfo_en: "Only special Winter's Feast dishes can be placed on this table.\n\nWhen the \"food\" on this table is \"eaten\" it gives a Winter's Cheer buff to the survivor.\n\nThe buff heals the survivor 0.5 Health per second, 10 Sanity per minute and 75 Hunger per day as well as halting the regular hunger drain.\n\nThe buff's duration is based on how grand the feast is. More tables connected together, more survivors feasting together and  a varied number of dishes will increase the duration of the buff.", specialinfo_ko: "특별한 겨울 축제 음식만 놓을 수 있다.\n\n테이블 위의 \"음식\"을 \"섭취\"하면 명절의 기운 버프를 얻을 수 있다.\n\n해당 버프의 효과로 체력이 초당 0.5 회복되고, 정신력이 분당 10 회복되며, 기본 허기 감소를 멈춤과 동시에 일당 75의 허기를 회복한다.\n\n버프의 지속시간은 축제 만찬이 얼마나 성찬이었는지에 따라 달라진다. 연결된 테이블의 수, 함께 식사하는 생존자의 수, 음식의 가짓수가 많을수록 길어진다.", deps: ["beefalowool", "boards"]},
  tacklecontainer: {type: "item", burnable: true, specialinfo_en: "A 6 slots container for holding Tackle.", specialinfo_ko: "찌와 미끼를 담는 6칸짜리 보관함.", deps: ["cookiecuttershell", "rope"]},
  tacklestation: {type: "thing", subcat: "craftingstation", burnable: true, specialinfo_en: "Standing near this device will provide the survivor with new Lures and Floats they can craft.", specialinfo_ko: "이 장치 근처에 있으면 새로운 찌와 미끼를 제작할 수 있다.", deps: ["boneshard", "driftwood_log", "oceanfishingbobber_ball", "oceanfishingbobber_canary", "oceanfishingbobber_crow", "oceanfishingbobber_goose", "oceanfishingbobber_malbatross", "oceanfishingbobber_oval", "oceanfishingbobber_robin", "oceanfishingbobber_robin_winter", "oceanfishinglure_spinner_blue", "oceanfishinglure_spinner_green", "oceanfishinglure_spinner_red", "oceanfishinglure_spoon_blue", "oceanfishinglure_spoon_green", "oceanfishinglure_spoon_red", "tacklesketch", "transistor"]},
