  telebase: {type: "thing", specialinfo_en: "This device requires 3 purple gems to be active\n\nA survivor that uses a Telelocator Staff will teleport to the nearest active Telelocator Focus and consume the gems.", specialinfo_ko: "보라 보석 3개가 있어야 활성화된다.\n\n순간이동 지팡이를 사용하면 가장 가까운 활성화된 순간이동 집중기로 이동하고 보석은 소모된다.", deps: ["goldnugget", "livinglog", "nightmarefuel"]},
  telestaff: {type: "item", finiteuses: 5, specialinfo: "PURPLESTAFF", specialinfo_en: "Teleports targets to a random location or to a fueled Telelocator Focus.", specialinfo_ko: "대상을 무작위 장소 또는 보석을 꽂은 순간이동 집중점으로 이동시킨다.", deps: ["livinglog", "nightmarefuel", "purplegem"]},
  tent: {type: "thing", subcat: "structure", finiteuses: 15, burnable: true, specialinfo_en: "A survivor can use the tent at Dusk or Night.\n\nSurvivor recovers 2 Health per second and 1 Sanity per second but consumes 0.33 Hunger per second. It also reduces 1 Wetness per second and increases temperature 1 degree per second up to 40 degrees.", specialinfo_ko: "저녁 혹은 밤에 사용 가능.\n\n매 초 2의 체력과 1의 정신력을 회복하지만 0.33의 허기를 소모한다. 습기를 초당 1 낮추고 체온을 최대 40도까지 초당 1 낮춘다.", deps: ["rope", "silk", "twigs"]},
  tentacle: {type: "creature", damage: 34, sanityaura: -0.66666666666667, deps: ["monstermeat", "tentaclespike", "tentaclespots"]},
