  tentacle_pillar_hole: {type: "POI", specialinfo: "TENTACLEPILLARHOLE", specialinfo_en: "A hole leading to a tunnel that leads somewhere else.", specialinfo_ko: "어딘가로 통하는 굴의 입구.", deps: ["tentacle_pillar"]},
