  terrariumchest: {type: "thing", subcat: "container", burnable: true, specialinfo: "TREASURECHEST", specialinfo_en: "A container with 9 slots.", specialinfo_ko: "9칸짜리 보관함.", deps: ["blowdart_pipe", "boards", "boomerang", "cutstone", "fireflies", "goldnugget", "grass_umbrella", "gunpowder", "healingsalve", "log", "marble", "messagebottleempty", "papyrus", "razor", "rope", "spear", "terrarium", "torch"]},
