  toadstool: {type: "giant", damage: 50, deps: ["blue_cap", "blueprint", "froglegs", "green_cap", "meat", "mushroomsprout", "red_cap", "shroom_skin", "sketch", "spore_medium", "spore_small", "spore_tall", "winter_ornament_boss_toadstool"]},
