  torch: {type: "item", subcat: "weapon", weapondamage: 17, waterproofer: 0.2, fueledmax: 75, fueledrate: 1, fueledtype1: "BURNABLE", specialinfo_en: "Creates a light when held.\n\nCan light targets on fire.", specialinfo_ko: "착용 시 빛이 난다.\n\n대상에 불을 붙일 수 있다.", deps: ["cutgrass", "twigs"]},
  tourtiere: {type: "item", subcat: "wintersfeastfood", finiteuses: 180, burnable: true, specialinfo: "WINTERSFEASTCOOKEDFOODS", specialinfo_en: "Captures the spirit of food when this is put on a Winter's Feast Table. The more, the merrier.", specialinfo_ko: "겨울 축제 탁자에 올려놓으면 진정한 맛을 느낄 수 있다. 많을수록 명절이 즐거워진다."},
  townportal: {type: "thing", subcat: "structure", specialinfo_en: "At the cost of 15 Sanity, a survivor can activate the device and then consume 40 Sanity per minute while they keep it active. A second survivor can use another Lazy Deserter or a Desert Stone to teleport to the active one. The teleport costs 50 Sanity.", specialinfo_ko: "정신력을 15 소모하여 장치를 활성화하고, 활성화 중일 때는 정신력을 분당 40 소모한다. 또다른 생존자가 다른 게으른 도망자나 사막석을 사용하면 활성화된 도망자 쪽으로 순간이동할 수 있다. 순간이동 시에는 정신력이 50 소모된다.", deps: ["cutstone", "orangemooneye", "townportaltalisman"]},
  townportaltalisman: {type: "item", stacksize: 10, specialinfo_en: "When another survivor is channeling a Lazy Deserter, use this to teleport to them.", specialinfo_ko: "다른 생존자가 게으른 도망자를 활성화한 상태에서 사용 시 활성화된 게으른 도망자 쪽으로 순간이동한다."},
  trailmix: {type: "food", stacksize: 40, perishable: 7200, hungervalue: 12.5, healthvalue: 30, sanityvalue: 5, foodtype: "VEGGIE", burnable: true, deps: ["spoiled_food"]},
  transistor: {type: "item", stacksize: 10, deps: ["cutstone", "goldnugget"]},
  trap: {type: "item", finiteuses: 8, specialinfo_en: "Once set on the ground, it will trigger when an appropriately sized creature move nearby, capturing them.\n\nCollecting a captured trap will put the creature or loot in your inventory.\n\nTraps can be baited with appropriate food.", specialinfo_ko: "바닥에 설치하면 지나가는 적당한 크기의 생물을 포획한다.\n\n생물을 포획한 덫을 회수하면 생물 혹은 전리품을 획득 가능.\n\n적절한 음식을 미끼로 둘 수 있다.", deps: ["cutgrass", "twigs"]},
  trap_bramble: {type: "item", damage: 40, finiteuses: 10, craftingprefab: "wormwood", deps: ["livinglog", "stinger"]},
  trap_starfish: {type: "thing", damage: 60},
  trap_teeth: {type: "item", damage: 60, finiteuses: 10, specialinfo: "TRAPTEETH", specialinfo_en: "After being planted on the ground, it will trigger when a creature walks near.\n\nIt needs to be reset after triggering. It can be picked up and moved.", specialinfo_ko: "땅에 설치하면 생물이 주변을 지나갈 때 작동한다.\n\n작동한 뒤에는 덫을 원상복구해줘야 한다. 주워서 옮길 수 있다.", deps: ["houndstooth", "log", "rope"]},
  treasurechest: {type: "thing", subcat: "container", burnable: true, specialinfo_en: "A container with 9 slots.", specialinfo_ko: "9칸짜리 보관함.", deps: ["boards", "chestupgrade_stacksize"]},
  tree_rock: {type: "thing", subcat: "tree", burnable: true, specialinfo_en: "The vines uproot more than boulders, depending on where they are planted.", specialinfo_ko: "덩굴이 바위 말고도 심은 곳에 따라 다양한 것들을 뽑아 올린다.", deps: ["twigs"]},
  treegrowthsolution: {type: "item", stacksize: 10, specialinfo_en: "Grows trees up one stage. Can also restore 8 Growth Formula, 32 Compost and 8 Manure to Farm Soil.\n\nUsed on Wormwood will heal 2 Health and 1 Health a second for 32 seconds.", specialinfo_ko: "나무가 한 단계 성장한다. 밭에 사용 시 성장 촉진제 8, 퇴비 32, 거름 8의 양분을 보충한다.\n\n웜우드에게 사용 시 체력을 2 회복하고 32초 동안 초당 1의 체력을 회복한다.", deps: ["fig", "glommerfuel"]},
  trident: {type: "item", subcat: "weapon", finiteuses: 200, specialinfo_en: "Can be Played to cause small geysers to shoot up from the ocean, doing damage to creatures and structures.", specialinfo_ko: "연주하면 바닷물이 작게 솟아올라 생물과 구조물에 데미지를 입힌다.", deps: ["gnarwail_horn", "kelp", "twigs"]},
