  walterhat: {type: "item", subcat: "hat", dapperness: 0.033333333333333, waterproofer: 0.2, insulator: 60, insulator_type: "summer", fueledmax: 4800, fueledrate: 1, fueledtype1: "USAGE", sewable: true, craftingprefab: "walter", specialinfo_en: "Walter's sanity loss due to damage is halved.", specialinfo_ko: "월터가 피해를 입을 때의 정신력 감소를 반으로 줄인다.", deps: ["silk"]},
  wanderingtrader: {type: "thing", specialinfo_en: "He travels between a few Points of Interest, looking for survivors to trade with. He gets new stock every couple of days, so be sure to check back in regularly!", specialinfo_ko: "몇몇 중요 지점 주변으로 옮겨다니며 거래할 생존자를 찾아다닌다. 이틀마다 재고를 새로 들여오니 주기적으로 방문하자!", deps: ["bluegem", "cutgrass", "cutreeds", "flint", "gears", "livinglog", "moonglass", "pigskin", "redgem", "twigs"]},
  wardrobe: {type: "thing", subcat: "structure", burnable: true, specialinfo_en: "A survivor can add, remove and change their outfit with collected skins.", specialinfo_ko: "모은 스킨을 입고, 벗고, 바꿔입을 수 있다.", deps: ["boards", "cutgrass"]},
