  warglet: {type: "creature", subcat: "hound", damage: 40, sanityaura: -0.66666666666667, deps: ["houndstooth", "monstermeat"]},
  waterballoon: {type: "item", subcat: "weapon", weapondamage: 0, weaponrange: 10, stacksize: 20, specialinfo_en: "When thrown it puts out fires in a small area where it lands.\n\nIt will also cool targets 5 degrees and adds 20 wetness.", specialinfo_ko: "던지면 착탄 지점 주변 작은 영역의 불을 끈다.\n\n맞은 대상은 온도 5 감소 및 습기 20 증가.", deps: ["ice", "mosquitosack"]},
  wateringcan: {type: "item", subcat: "tool", weapondamage: 10, finiteuses: 40, burnable: true, specialinfo_en: "Adds 25 points of wetness to Garden Soil per use.\n\nCan also put out fires and stop smouldering.", specialinfo_ko: "텃밭 흙에 1회당 수분 25 추가.\n\n불을 끄거나 불씨를 죽일 때도 사용 가능.", deps: ["boards", "rope"]},
